      options: [{ id: `A`, text: `f(x) = (3/7)x &minus; 5` }, { id: `B`, text: `f(x) = (7/3)x &minus; 5` }, { id: `C`, text: `f(x) = &minus;(3/7)x &minus; 5` }, { id: `D`, text: `f(x) = &minus;(7/3)x &minus; 5` }],
